const request = $input.first().json;
const rawHeaders = (request.headers && typeof request.headers === 'object' && !Array.isArray(request.headers)) ? request.headers : {};
const headers = Object.fromEntries(
  Object.entries(rawHeaders).map(([key, value]) => [String(key).toLowerCase(), value])
);
const sanitizedHeaders = Object.fromEntries(
  Object.entries(rawHeaders).filter(([key]) => {
    const normalizedKey = String(key).toLowerCase();
    return normalizedKey !== 'x-api-key' && normalizedKey !== 'authorization';
  })
);
const sanitizedRequest = {
  ...request,
  headers: sanitizedHeaders
};
const headerValue = (value) => Array.isArray(value) ? String(value[0] || '').trim() : String(value || '').trim();
const expectedApiKey = String($env.N8N_WEBHOOK_API_KEY || '').trim();
const xApiKey = headerValue(headers['x-api-key']);
const authorization = headerValue(headers.authorization);
const bearerMatch = authorization.match(/^Bearer\s+(.+)$/i);
const bearerToken = bearerMatch ? String(bearerMatch[1] || '').trim() : '';
const matchedXApiKey = Boolean(expectedApiKey) && xApiKey === expectedApiKey;
const matchedBearer = Boolean(expectedApiKey) && bearerToken === expectedApiKey;
const authenticated = matchedXApiKey || matchedBearer;

if (authenticated) {
  return [{
    json: {
      ...sanitizedRequest,
      webhook_auth: {
        authenticated: true,
        header: matchedXApiKey ? 'X-API-Key' : 'Authorization'
      }
    },
    pairedItem: {
      item: 0
    }
  }];
}

const message = 'Unauthorized: Invalid or missing API key';

return [{
  json: {
    ...sanitizedRequest,
    status: 'error',
    message,
    code: 401,
    webhook_auth: {
      authenticated: false
    }
  },
  pairedItem: {
    item: 0
  }
}];

const input = $input.first().json.body || {};

const actor = String(input.actor || '').trim();
const action = String(input.action || '').trim();
const target = String(input.target || '').trim();
const decision = String(input.decision || '').trim();

if (!actor || !action || !target || !decision) {
  return [{
    json: {
      error: 'Missing required fields: actor, action, target, decision'
    }
  }];
}

const validDecisions = ['allowed', 'denied', 'requires_approval'];
if (!validDecisions.includes(decision)) {
  return [{
    json: {
      error: 'Invalid decision. Must be: allowed, denied, or requires_approval'
    }
  }];
}

const payload = (input.payload && typeof input.payload === 'object' && !Array.isArray(input.payload))
  ? input.payload
  : {};

const requestId = String(payload.request_id || '').trim();
const policyId = String(payload.policy_id || '').trim();
const policyVersion = String(payload.policy_version || '').trim();
const policyReason = String(payload.policy_reason || '').trim() || null;

if (!requestId || !policyId || !policyVersion) {
  return [{
    json: {
      error: 'payload.request_id, payload.policy_id, payload.policy_version are required'
    }
  }];
}

let riskScore = null;
if (payload.risk_score !== undefined && payload.risk_score !== null && payload.risk_score !== '') {
  const parsedRisk = Number(payload.risk_score);
  if (!Number.isFinite(parsedRisk)) {
    return [{
      json: {
        error: 'payload.risk_score must be numeric when provided'
      }
    }];
  }
  riskScore = Math.round(parsedRisk);
}

return [{
  json: {
    actor,
    action,
    target,
    decision,
    payload,
    request_id: requestId,
    policy_id: policyId,
    policy_version: policyVersion,
    policy_reason: policyReason,
    risk_score: riskScore
  }
}];

const data = $input.first().json;

if (data.error) {
  return [{
    json: {
      status: 'error',
      message: data.error
    }
  }];
}

return [{
  json: data
}];

